#!/usr/bin/env bun
// PreToolUse hook: warn when Agent is called with session-work prompts
// that were not generated by session.generate_prompt.
//
// Detection: prompts containing "session_commit" are session work.
// Tool-generated prompts contain the "minsky:prompt:v1" watermark.
// Hand-crafted session prompts lack the watermark → warn.

import { readInput } from "./types";
import type { ToolHookInput } from "./types";

const input = await readInput<ToolHookInput>();
const prompt = (input.tool_input.prompt as string) ?? "";

// Only check prompts that dispatch session work (mention session_commit)
const isSessionWork = prompt.includes("session_commit");
const hasWatermark = prompt.includes("minsky:prompt:v1");

if (isSessionWork && !hasWatermark) {
  console.log(
    "⚠️ This Agent prompt dispatches session work but was not generated by session.generate_prompt."
  );
  console.log(
    "Use mcp__minsky__session_generate_prompt to generate a prompt with correct metadata."
  );
  console.log("If the tool is unavailable, restart the MCP server with /mcp.");
}

process.exit(0);
